<?php
namespace App\Domain\Equipment;use App\Domain\Equipment\Data\EquipmentLoadoutResult;use App\Models\CharacterClass;use App\Models\Item;
final class EquipmentLoadoutValidator{private $hands;private $capabilities;public function __construct(HandItemConfigurationValidator $hands,CharacterClassCapabilityService $capabilities){$this->hands=$hands;$this->capabilities=$capabilities;}public function evaluate($slot,Item $candidate,$equipment,$instances,$catalog,CharacterClass $class=null){if(!in_array($slot,[CharacterEquipmentSlot::MAIN_HAND,CharacterEquipmentSlot::OFF_HAND],true))return new EquipmentLoadoutResult([]);$kind=$this->hands->classify($candidate);$main=$this->itemAt(CharacterEquipmentSlot::MAIN_HAND,$equipment,$instances,$catalog,$slot,$candidate);$off=$this->itemAt(CharacterEquipmentSlot::OFF_HAND,$equipment,$instances,$catalog,$slot,$candidate);if($slot===CharacterEquipmentSlot::MAIN_HAND){if($kind===HandRequirement::OFF_HAND_ONLY)return$this->deny('invalid_off_hand_item','Este objeto solo puede equiparse en la mano secundaria.');if($kind===HandRequirement::TWO_HAND&&$off)return new EquipmentLoadoutResult(['allowed'=>false,'reason'=>'Esta arma requiere ambas manos. Al equiparla se desequipara '.$off->name.'.','reason_code'=>'two_handed_weapon_blocks_off_hand','conflicting_slots'=>[CharacterEquipmentSlot::OFF_HAND],'conflicting_items'=>[['slot'=>CharacterEquipmentSlot::OFF_HAND,'item_name'=>$off->name]],'requires_confirmation'=>true,'required_actions'=>[['action'=>'unequip','slot'=>CharacterEquipmentSlot::OFF_HAND]]]);return new EquipmentLoadoutResult([]);}if($kind===HandItemConfigurationValidator::LEGACY_MAIN_HAND_ONLY||$kind===HandRequirement::TWO_HAND)return$this->deny('invalid_off_hand_item','Este objeto no puede equiparse en la mano secundaria.');if($main&&$this->hands->classify($main)===HandRequirement::TWO_HAND)return$this->deny('off_hand_blocked_by_two_handed_weapon','No puedes equipar este objeto porque el arma principal requiere ambas manos.');if($kind===HandRequirement::OFF_HAND_ONLY)return new EquipmentLoadoutResult([]);if(!$main||$this->hands->classify($main)!==HandRequirement::ONE_HAND)return$this->deny('main_hand_one_hand_required','Debes equipar primero un arma de una mano en la mano principal.');if(!$this->capabilities->canDualWield($class))return$this->deny('dual_wield_not_allowed','Tu clase no puede equipar una segunda arma.');return new EquipmentLoadoutResult([]);}private function itemAt($wanted,$equipment,$instances,$catalog,$target,Item $candidate){if($wanted===$target)return$candidate;$row=$equipment->firstWhere('slot',$wanted);if(!$row)return null;$instance=$instances->firstWhere('id',$row->item_instance_id);return$instance?$catalog->get($instance->item_id):null;}private function deny($code,$message){return new EquipmentLoadoutResult(['allowed'=>false,'reason'=>$message,'reason_code'=>$code]);}}
